<?php namespace App\Repositories\Student;use App\Repositories\BaseRepository;use App\Models\Student\Student;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudentRepository extends BaseRepository{    public function __construct(Student $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findBySection(int $sectionId): Collection    {        return $this->findByField('section_id', $sectionId);    }    public function findByRollNumber(string $rollNumber): ?Student    {        return $this->query()->where('roll_number', $rollNumber)->first();    }    public function findByHouse(int $houseId): Collection    {        return $this->findByField('house_id', $houseId);    }    public function searchStudents(string $keyword): Collection    {        return $this->query()->where(function ($q) use ($keyword) {                $q->where('first_name', 'like', "%{$keyword}%")->orWhere('last_name', 'like', "%{$keyword}%")->orWhere('admission_no', 'like', "%{$keyword}%")->orWhere('roll_number', 'like', "%{$keyword}%")->orWhereRaw("CONCAT(first_name, ' ', last_name) LIKE ?", ["%{$keyword}%"]);            })->get();    }    public function getActiveStudents(): Collection    {        return $this->query()->where('status', 'active')->get();    }    public function getAlumni(): Collection    {        return $this->query()->where('status', 'alumni')->get();    }    public function getByParent(int $parentId): Collection    {        return $this->query()->whereHas('parents', function ($q) use ($parentId) {                $q->where('parent_id', $parentId);            })->get();    }    public function getByClassAndSection(int $classId, int $sectionId): Collection    {        return $this->query()->where('class_id', $classId)->where('section_id', $sectionId)->orderBy('roll_number', 'asc')->get();    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function countByGender(): Collection    {        return $this->query()->selectRaw('gender, COUNT(*) as total')->groupBy('gender')->get();    }    public function countByClass(): Collection    {        return $this->query()->selectRaw('class_id, COUNT(*) as total')->groupBy('class_id')->get();    }    public function getStudentsWithPendingFees(): Collection    {        return $this->query()->whereHas('feeCollections', function ($q) {                $q->where('balance_amount', '>', 0);            })->get();    }    public function bulkUpdateClass(array $studentIds, int $classId, ?int $sectionId = null): bool    {        $data = ['class_id' => $classId];        if ($sectionId) {            $data['section_id'] = $sectionId;        }        return $this->query()->whereIn('id', $studentIds)->update($data);    }}